import{_ as a,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Dépannage Invalid Grant: Réactivation de compte désactivé | Antigravity-Manager","description":"Apprenez la signification de l'erreur invalid_grant et la logique de traitement automatique. Après confirmation de l'expiration de refresh_token, déclenchez la réactivation automatique en ajoutant à nouveau le compte via OAuth, et vérifiez que la réactivation prend effet pour le Proxy.","frontmatter":{"title":"Dépannage Invalid Grant: Réactivation de compte désactivé | Antigravity-Manager","sidebarTitle":"Comment réactiver un compte désactivé","subtitle":"invalid_grant et désactivation automatique de compte : pourquoi cela arrive, comment réactiver","description":"Apprenez la signification de l'erreur invalid_grant et la logique de traitement automatique. Après confirmation de l'expiration de refresh_token, déclenchez la réactivation automatique en ajoutant à nouveau le compte via OAuth, et vérifiez que la réactivation prend effet pour le Proxy.","tags":["FAQ","Dépannage","OAuth","Gestion des comptes","invalid_grant"],"prerequisite":["start-add-account","start-first-run-data","advanced-scheduling"],"order":1},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}`),o={name:"fr/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function n(s,e,l,d,c,u){return r(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="invalid-grant-et-desactivation-automatique-de-compte-pourquoi-cela-arrive-comment-reactiver" tabindex="-1">invalid_grant et désactivation automatique de compte : pourquoi cela arrive, comment réactiver <a class="header-anchor" href="#invalid-grant-et-desactivation-automatique-de-compte-pourquoi-cela-arrive-comment-reactiver" aria-label="Permalink to &quot;invalid_grant et désactivation automatique de compte : pourquoi cela arrive, comment réactiver&quot;">​</a></h1><h2 id="ce-que-vous-saurez-faire-a-la-fin" tabindex="-1">Ce que vous saurez faire à la fin <a class="header-anchor" href="#ce-que-vous-saurez-faire-a-la-fin" aria-label="Permalink to &quot;Ce que vous saurez faire à la fin&quot;">​</a></h2><ul><li>En voyant <code>invalid_grant</code>, savoir à quelle catégorie de problème refresh_token cela correspond</li><li>Comprendre pourquoi « le compte est soudainement indisponible » : dans quels cas il est automatiquement désactivé, comment le système traite après désactivation</li><li>Réactiver le compte par le chemin le plus court, et confirmer que la réactivation a pris effet pour le Proxy en cours</li></ul><h2 id="vos-symptomes-actuels" tabindex="-1">Vos symptômes actuels <a class="header-anchor" href="#vos-symptomes-actuels" aria-label="Permalink to &quot;Vos symptômes actuels&quot;">​</a></h2><ul><li>L&#39;appel au Proxy local échoue soudainement, le message d&#39;erreur contient <code>invalid_grant</code></li><li>Le compte est encore dans la liste Accounts, mais le Proxy continue de le sauter (ou vous avez l&#39;impression qu&#39;il « n&#39;est plus jamais utilisé »)</li><li>Avec peu de comptes, après une <code>invalid_grant</code>, la disponibilité globale se dégrade nettement</li></ul><h2 id="qu-est-ce-que-invalid-grant" tabindex="-1">Qu&#39;est-ce que invalid_grant ? <a class="header-anchor" href="#qu-est-ce-que-invalid-grant" aria-label="Permalink to &quot;Qu&#39;est-ce que invalid_grant ?&quot;">​</a></h2><p><strong>invalid_grant</strong> est une erreur renvoyée par Google OAuth lors du rafraîchissement de <code>access_token</code>. Pour Antigravity Tools, cela signifie que le <code>refresh_token</code> d&#39;un compte a probablement été révoqué ou a expiré, continuer à réessayer ne fera qu&#39;échouer de manière répétée, donc le système marquera le compte comme indisponible et le retirera du pool proxy.</p><h2 id="idee-principale-le-systeme-ne-«-saute-pas-temporairement-»-mais-«-desactive-de-maniere-persistante-»" tabindex="-1">Idée principale : le système ne « saute pas temporairement », mais « désactive de manière persistante » <a class="header-anchor" href="#idee-principale-le-systeme-ne-«-saute-pas-temporairement-»-mais-«-desactive-de-maniere-persistante-»" aria-label="Permalink to &quot;Idée principale : le système ne « saute pas temporairement », mais « désactive de manière persistante »&quot;">​</a></h2><p>Lorsque le Proxy découvre que la chaîne d&#39;erreur de rafraîchissement de token contient <code>invalid_grant</code>, il fera deux choses :</p><ol><li><strong>Marquer le compte comme disabled</strong> (persister dans JSON du compte)</li><li><strong>Retirer le compte du pool de tokens en mémoire</strong> (éviter de sélectionner à plusieurs reprises le même mauvais compte)</li></ol><p>C&#39;est pourquoi vous voyez « le compte est là, mais le Proxy ne l&#39;utilise plus ».</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code> : le compte est « complètement désactivé » (la cause typique est <code>invalid_grant</code>). Sera sauté lors du chargement du pool de comptes.</li><li><code>proxy_disabled=true</code> : le compte est seulement « indisponible pour le Proxy » (désactivation manuelle/operation batch/logique de protection du quota), la sémantique est différente.</li></ul><p>Ces deux états sont jugés séparément lors du chargement du pool de comptes : d&#39;abord juger <code>disabled</code>, puis juger la protection du quota et <code>proxy_disabled</code>.</p></div><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-confirmer-si-invalid-grant-est-declenche-par-le-rafraichissement-de-refresh-token" tabindex="-1">Étape 1 : Confirmer si invalid_grant est déclenché par le rafraîchissement de refresh_token <a class="header-anchor" href="#etape-1-confirmer-si-invalid-grant-est-declenche-par-le-rafraichissement-de-refresh-token" aria-label="Permalink to &quot;Étape 1 : Confirmer si invalid_grant est déclenché par le rafraîchissement de refresh_token&quot;">​</a></h3><p><strong>Pourquoi</strong> : <code>invalid_grant</code> peut apparaître dans plusieurs chaînes d&#39;appel, mais la « désactivation automatique » de ce projet n&#39;est déclenchée que lors de l&#39;<strong>échec du rafraîchissement de access_token</strong>.</p><p>Dans le journal Proxy, vous verrez un journal d&#39;erreur similaire (mots-clés sont <code>Token 刷新失败</code> + <code>invalid_grant</code>) :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token 刷新失败 (&lt;email&gt;): &lt;...invalid_grant...&gt;，尝试下一个账号</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : après qu&#39;un compte a <code>invalid_grant</code>, il n&#39;est plus sélectionné rapidement (car retiré du pool de tokens).</p><h3 id="etape-2-verifier-le-champ-disabled-dans-le-fichier-de-compte-optionnel-mais-le-plus-precis" tabindex="-1">Étape 2 : Vérifier le champ disabled dans le fichier de compte (optionnel, mais le plus précis) <a class="header-anchor" href="#etape-2-verifier-le-champ-disabled-dans-le-fichier-de-compte-optionnel-mais-le-plus-precis" aria-label="Permalink to &quot;Étape 2 : Vérifier le champ disabled dans le fichier de compte (optionnel, mais le plus précis)&quot;">​</a></h3><p><strong>Pourquoi</strong> : la désactivation automatique est « persistée », après avoir confirmé le contenu du fichier, vous pouvez exclure la mauvaise interprétation de « juste rotation temporaire ».</p><p>Le fichier de compte se trouve dans le répertoire <code>accounts/</code> du répertoire de données de l&#39;application (l&#39;emplacement du répertoire de données voir <strong><a href="./../../start/first-run-data/">Premier démarrage : répertoire de données, journaux, barre des tâches et démarrage automatique</a></strong>). Lorsque le compte est désactivé, le fichier affichera ces trois champs :</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : <code>disabled</code> est <code>true</code>, et <code>disabled_reason</code> contient le préfixe <code>invalid_grant:</code>.</p><h3 id="etape-3-reactiver-le-compte-methode-recommandee-ajouter-a-nouveau-le-meme-compte" tabindex="-1">Étape 3 : Réactiver le compte (méthode recommandée : ajouter à nouveau le même compte) <a class="header-anchor" href="#etape-3-reactiver-le-compte-methode-recommandee-ajouter-a-nouveau-le-meme-compte" aria-label="Permalink to &quot;Étape 3 : Réactiver le compte (méthode recommandée : ajouter à nouveau le même compte)&quot;">​</a></h3><p><strong>Pourquoi</strong> : la « réactivation » de ce projet n&#39;est pas de cliquer manuellement sur un interrupteur dans le Proxy, mais de déclencher la réactivation automatique par « mise à jour explicite du token ».</p><p>Accédez à la page <strong>Accounts</strong>, ajoutez à nouveau le compte avec vos nouvelles informations d&#39;identification (choisissez l&#39;une des deux méthodes) :</p><ol><li>Suivez à nouveau le processus d&#39;autorisation OAuth (voir <strong><a href="./../../start/add-account/">Ajouter un compte : double canal OAuth/Refresh Token et meilleures pratiques</a></strong>)</li><li>Ajoutez à nouveau avec un nouveau <code>refresh_token</code> (le système utilisera l&#39;e-mail renvoyé par Google comme base pour faire upsert)</li></ol><p>Lorsque le système détecte que <code>refresh_token</code> ou <code>access_token</code> de votre upsert est différent de l&#39;ancienne valeur, et que le compte était auparavant dans <code>disabled=true</code>, il effacera automatiquement :</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>Ce que vous devriez voir</strong> : le compte n&#39;est plus dans l&#39;état disabled, et (si le Proxy est en cours d&#39;exécution) le pool de comptes sera automatiquement rechargé, rendant la réactivation immédiate.</p><h3 id="etape-4-verifier-si-la-reactivation-a-pris-effet-pour-le-proxy" tabindex="-1">Étape 4 : Vérifier si la réactivation a pris effet pour le Proxy <a class="header-anchor" href="#etape-4-verifier-si-la-reactivation-a-pris-effet-pour-le-proxy" aria-label="Permalink to &quot;Étape 4 : Vérifier si la réactivation a pris effet pour le Proxy&quot;">​</a></h3><p><strong>Pourquoi</strong> : si vous n&#39;avez qu&#39;un seul compte, ou si les autres comptes ne sont pas disponibles, après réactivation vous devriez voir immédiatement « la disponibilité est revenue ».</p><p>Méthode de vérification :</p><ol><li>Lancez une requête qui déclenche le rafraîchissement de token (par exemple attendez que le token soit proche de l&#39;expiration avant de faire la requête)</li><li>Observez que le journal n&#39;affiche plus l&#39;invite « sauter le compte disabled »</li></ol><p><strong>Ce que vous devriez voir</strong> : la requête passe normalement, et le journal n&#39;affiche plus le processus de désactivation <code>invalid_grant</code> pour ce compte.</p><h2 id="attention-aux-pieges" tabindex="-1">Attention aux pièges <a class="header-anchor" href="#attention-aux-pieges" aria-label="Permalink to &quot;Attention aux pièges&quot;">​</a></h2><h3 id="❌-confondre-disabled-avec-«-rotation-temporaire-»" tabindex="-1">❌ Confondre disabled avec « rotation temporaire » <a class="header-anchor" href="#❌-confondre-disabled-avec-«-rotation-temporaire-»" aria-label="Permalink to &quot;❌ Confondre disabled avec « rotation temporaire »&quot;">​</a></h3><p>Si vous ne regardez que « le compte est là » dans l&#39;UI, il est facile de mal interpréter comme « le système ne l&#39;utilise que temporairement ». Mais <code>disabled=true</code> est écrit sur le disque, continuera à prendre effet après redémarrage.</p><h3 id="❌-completer-seulement-access-token-ne-pas-mettre-a-jour-refresh-token" tabindex="-1">❌ Compléter seulement access_token, ne pas mettre à jour refresh_token <a class="header-anchor" href="#❌-completer-seulement-access-token-ne-pas-mettre-a-jour-refresh-token" aria-label="Permalink to &quot;❌ Compléter seulement access_token, ne pas mettre à jour refresh_token&quot;">​</a></h3><p>Le point de déclenchement de <code>invalid_grant</code> est le <code>refresh_token</code> utilisé lors du rafraîchissement de <code>access_token</code>. Si vous avez seulement obtenu temporairement un <code>access_token</code> encore utilisable, mais que <code>refresh_token</code> est toujours expiré, cela déclenchera encore la désactivation.</p><h2 id="points-de-controle-✅" tabindex="-1">Points de contrôle ✅ <a class="header-anchor" href="#points-de-controle-✅" aria-label="Permalink to &quot;Points de contrôle ✅&quot;">​</a></h2><ul><li>[ ] Vous pouvez confirmer dans le journal que <code>invalid_grant</code> provient de l&#39;échec du rafraîchissement de refresh_token</li><li>[ ] Vous connaissez la différence sémantique entre <code>disabled</code> et <code>proxy_disabled</code></li><li>[ ] Vous pouvez réactiver le compte en ajoutant à nouveau le compte (OAuth ou refresh_token)</li><li>[ ] Vous pouvez vérifier que la réactivation a pris effet pour le Proxy en cours d&#39;exécution</li></ul><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la leçon&quot;">​</a></h2><ul><li>Lorsque <code>invalid_grant</code> est déclenché, le Proxy <strong>persistera le compte comme disabled</strong> et le retirera du pool de tokens, évitant les échecs répétés</li><li>La clé de réactivation est « mise à jour explicite du token » (OAuth à nouveau ou ajouter à nouveau avec nouveau refresh_token), le système effacera automatiquement les champs <code>disabled_*</code></li><li>Le JSON du compte dans le répertoire de données est la source la plus autoritaire d&#39;état (désactivation/raison/heure y sont)</li></ul><h2 id="prochaine-lecon" tabindex="-1">Prochaine leçon <a class="header-anchor" href="#prochaine-lecon" aria-label="Permalink to &quot;Prochaine leçon&quot;">​</a></h2><blockquote><p>La prochaine leçon, nous apprendrons <strong><a href="./../auth-401/">401/Échec d&#39;authentification : auth_mode, compatibilité Header et liste de configuration client</a></strong>.</p><p>Vous apprendrez :</p><ul><li>401 est généralement quelle couche de « mode/Key/Header » ne correspond pas</li><li>Quels en-têtes d&#39;authentification différents clients doivent porter</li><li>Comment utiliser le chemin le plus court pour auto-vérifier et corriger</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Heure de mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Ligne</th></tr></thead><tbody><tr><td>Conception : problème invalid_grant et comportement de modification</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-invalid-grant.md#L1-L52" target="_blank" rel="noreferrer"><code>docs/proxy-invalid-grant.md</code></a></td><td>1-52</td></tr><tr><td>Sauter <code>disabled=true</code> lors du chargement du pool de comptes</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L70-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>70-158</td></tr><tr><td>Identifier <code>invalid_grant</code> et désactiver le compte lors de l&#39;échec du rafraîchissement de token</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L840-L890" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>840-890</td></tr><tr><td>Persister <code>disabled/disabled_at/disabled_reason</code> et retirer de la mémoire</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td>Troncature <code>disabled_reason</code> (éviter l&#39;expansion du fichier de compte)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>Nettoyage automatique <code>disabled_*</code> lors de l&#39;upsert (changement de token considéré comme utilisateur a corrigé les informations d&#39;identification)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L178-L206" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>178-206</td></tr><tr><td>Rechargement automatique des comptes proxy après nouvel ajout de compte (effet immédiat en cours d&#39;exécution)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L21-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>21-59</td></tr></tbody></table></details>`,49)])])}const h=a(o,[["render",n]]);export{m as __pageData,h as default};
